import{_ as a,a as t,b as n,c as d}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as o,o as l,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"Een Yandex-kanaal toevoegen","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/upload/yandex.md","filePath":"nl-NL/upload/yandex.md","lastUpdated":1781962217000}'),s={name:"nl-NL/upload/yandex.md"};function p(c,e,h,k,b,u){return l(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="een-yandex-kanaal-toevoegen" tabindex="-1">Een Yandex-kanaal toevoegen <a class="header-anchor" href="#een-yandex-kanaal-toevoegen" aria-label="Permalink to &quot;Een Yandex-kanaal toevoegen&quot;">​</a></h1><h2 id="wat-je-vooraf-nodig-hebt" tabindex="-1">Wat je vooraf nodig hebt <a class="header-anchor" href="#wat-je-vooraf-nodig-hebt" aria-label="Permalink to &quot;Wat je vooraf nodig hebt&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Vereiste</th><th>Waarom je dit nodig hebt</th></tr></thead><tbody><tr><td>Yandex-account</td><td>Voor aanmelden en autoriseren van Yandex Disk</td></tr><tr><td>Yandex OAuth-app</td><td>Voor het genereren van <code>Client ID</code> en <code>Client Secret</code></td></tr><tr><td>Je ImgBed-domein</td><td>Voor de OAuth-redirect-URI</td></tr><tr><td>Beschikbare Yandex Disk-opslag</td><td>De daadwerkelijke opslaglocatie voor bestanden</td></tr></tbody></table><h2 id="instellen" tabindex="-1">Instellen <a class="header-anchor" href="#instellen" aria-label="Permalink to &quot;Instellen&quot;">​</a></h2><h3 id="stap-1-maak-een-yandex-oauth-app" tabindex="-1">Stap 1: Maak een Yandex OAuth-app <a class="header-anchor" href="#stap-1-maak-een-yandex-oauth-app" aria-label="Permalink to &quot;Stap 1: Maak een Yandex OAuth-app&quot;">​</a></h3><ol><li>Open de pagina voor het maken van een Yandex OAuth-app:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>Word je doorgestuurd om in te loggen, meld je dan eerst aan met je Yandex-account.</li><li>Maak een nieuwe app.</li><li>Geef de app een herkenbare naam, bijvoorbeeld <code>imgbed-yandex</code>.</li><li>Zoek de callback- of redirect-URL-instellingen.</li><li>Vul in:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="stap-2-controleer-rechten" tabindex="-1">Stap 2: Controleer rechten <a class="header-anchor" href="#stap-2-controleer-rechten" aria-label="Permalink to &quot;Stap 2: Controleer rechten&quot;">​</a></h3><p>Voor de huidige Yandex-integratie van ImgBed houd je onder <code>Yandex.Disk REST API</code> deze vier rechten aan:</p><table tabindex="0"><thead><tr><th>Recht</th><th>Doel</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>Laat ImgBed bestanden opslaan in de appmap</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>Leest bestanden en downloadlinks</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>Uploadt bestanden, maakt mappen en verwijdert bestanden</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>Leest diskquota en gebruikte ruimte</td></tr></tbody></table><p>Zie je onder <code>Yandex ID API</code> ook deze rechten, dan zijn ze optioneel:</p><table tabindex="0"><thead><tr><th>Rechttekst</th><th>Aanbeveling</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>Optioneel</td></tr><tr><td><code>Access to email address</code></td><td>Optioneel</td></tr></tbody></table><p>Uploaden, downloaden, verwijderen en quota werken vooral op basis van de vier <code>Yandex.Disk REST API</code>-rechten hierboven.</p><p><img src="'+a+'" alt="Yandex Disk-rechten instellen" loading="lazy"></p><h3 id="stap-3-kopieer-appgegevens" tabindex="-1">Stap 3: Kopieer appgegevens <a class="header-anchor" href="#stap-3-kopieer-appgegevens" aria-label="Permalink to &quot;Stap 3: Kopieer appgegevens&quot;">​</a></h3><p>Kopieer na het aanmaken van de app:</p><table tabindex="0"><thead><tr><th>Yandex-veld</th><th>ImgBed-veld</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+t+'" alt="Client ID en Secret noteren" loading="lazy"></p><h3 id="stap-4-vul-het-yandex-kanaal-in" tabindex="-1">Stap 4: Vul het Yandex-kanaal in <a class="header-anchor" href="#stap-4-vul-het-yandex-kanaal-in" aria-label="Permalink to &quot;Stap 4: Vul het Yandex-kanaal in&quot;">​</a></h3><p>Kies in Uploadinstellingen <code>Yandex</code> en vul in:</p><table tabindex="0"><thead><tr><th>ImgBed-veld</th><th>Wat je invult</th></tr></thead><tbody><tr><td>Kanaalnaam</td><td>Een herkenbare naam, bijvoorbeeld <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td>De Yandex-app <code>Client ID</code></td></tr><tr><td>Client Secret</td><td>De Yandex-app <code>Client Secret</code></td></tr><tr><td>Refresh Token</td><td>Laat voorlopig leeg</td></tr><tr><td>Hoofdmap</td><td>Optioneel. Standaard <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+n+'" alt="Kanaalconfiguratie bewerken" loading="lazy"></p><h3 id="stap-5-haal-het-refresh-token-op" tabindex="-1">Stap 5: Haal het Refresh Token op <a class="header-anchor" href="#stap-5-haal-het-refresh-token-op" aria-label="Permalink to &quot;Stap 5: Haal het Refresh Token op&quot;">​</a></h3><ol><li>Klik in ImgBed op <code>Get Token</code>.</li><li>Meld je aan met het Yandex-account dat je wilt koppelen.</li><li>Keur de autorisatie goed.</li><li>De callbackpagina toont een <code>Refresh Token</code>.</li><li>Kopieer het.</li><li>Ga terug naar ImgBed en plak het in <code>Refresh Token</code>.</li></ol><p><img src="'+d+`" alt="Refresh Token na autorisatie kopiëren" loading="lazy"></p><h3 id="stap-6-sla-het-kanaal-op" tabindex="-1">Stap 6: Sla het kanaal op <a class="header-anchor" href="#stap-6-sla-het-kanaal-op" aria-label="Permalink to &quot;Stap 6: Sla het kanaal op&quot;">​</a></h3><p>Sla het kanaal op zodra alle velden zijn ingevuld.</p><h2 id="snelle-flow" tabindex="-1">Snelle flow <a class="header-anchor" href="#snelle-flow" aria-label="Permalink to &quot;Snelle flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open Yandex OAuth Console</span></span>
<span class="line"><span>-&gt; Maak een app</span></span>
<span class="line"><span>-&gt; Voeg https://your-domain.com/api/oauth/yandex/callback toe</span></span>
<span class="line"><span>-&gt; Controleer Yandex Disk-rechten</span></span>
<span class="line"><span>-&gt; Kopieer Client ID en Client Secret</span></span>
<span class="line"><span>-&gt; Vul Client ID / Client Secret in ImgBed in</span></span>
<span class="line"><span>-&gt; Klik Get Token</span></span>
<span class="line"><span>-&gt; Kopieer het Refresh Token van de callbackpagina</span></span>
<span class="line"><span>-&gt; Plak het terug in ImgBed en sla op</span></span></code></pre></div><h2 id="referenties" tabindex="-1">Referenties <a class="header-anchor" href="#referenties" aria-label="Permalink to &quot;Referenties&quot;">​</a></h2><ol><li>Yandex-app registreren: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Authorization code via URL ophalen: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth token endpoint: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const v=o(s,[["render",p]]);export{x as __pageData,v as default};
